mapper.select:
select d.data_id, d.contract, d.gym_id, d.sender_id, d.receiver_id,
       d.receiver_name, d.status, d.manager_id, d.start_date, d.end_date
  from "h_contract_data" d
 where d.contract = 5
   and (d.receiver_id = #{receiverId}

        or d.source_coupon_id = #{sourceCouponId}

       )
   and d.status in ('DRAFT', 'ISSUED', 'SIGNED', 'ACTIVE')
 order by d.data_id desc
 limit 1

select count(*)
  from "h_coupon" c
  join "h_coupon_type" ct on c.coupon_num = ct.coupon_num
 where c.coupon_id = #{sourceCouponId}
   and c.from_id = #{senderId}
   and c.to_id = #{receiverId}
   and ct.category = '체험권'
   and ct.gym_id = #{gymId}
